#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void backtrack(int n, int open, int close, char *buf, char ***res, int *sz) {
    if (open == n && close == n) {
        (*sz)++;
        *res = realloc(*res, (*sz) * sizeof(char *));
        (*res)[(*sz) - 1] = strdup(buf);
        return;
    }
    if (open < n) {
        buf[open + close] = '(';
        backtrack(n, open + 1, close, buf, res, sz);
    }
    if (close < open) {
        buf[open + close] = ')';
        backtrack(n, open, close + 1, buf, res, sz);
    }
}

char **generate(int n, int *returnSize) {
    *returnSize = 0;
    char **result = NULL;
    char *buf = malloc(2 * n + 1);
    buf[2 * n] = '\0';
    backtrack(n, 0, 0, buf, &result, returnSize);
    free(buf);
    return result;
}

int main() {
    int T, n;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &n);
        int sz;
        char **ans = generate(n, &sz);
        for (int i = 0; i < sz; ++i) {
            printf("%s", ans[i]);
            if (i + 1 < sz) printf(" ");
            free(ans[i]);
        }
        free(ans);
        if (T) printf("\n");
    }
    return 0;
}

