#include <bits/stdc++.h>
using namespace std;

void backtrack(int n, int open, int close, string &cur, vector<string> &out) {
    if (open == n && close == n) {
        out.push_back(cur);
        return;
    }
    if (open < n) {
        cur.push_back('(');
        backtrack(n, open + 1, close, cur, out);
        cur.pop_back();
    }
    if (close < open) {
        cur.push_back(')');
        backtrack(n, open, close + 1, cur, out);
        cur.pop_back();
    }
}

vector<string> generate(int n) {
    vector<string> res;
    string cur;
    backtrack(n, 0, 0, cur, res);
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T, n;
    if (!(cin >> T)) return 0;
    while (T--) {
        cin >> n;
        vector<string> ans = generate(n);
        for (size_t i = 0; i < ans.size(); ++i) {
            cout << ans[i];
            if (i + 1 < ans.size()) cout << ' ';
        }
        if (T) cout << '\n';
    }
    return 0;
}

