import java.io.*;
import java.util.*;

public class Main {
    private static void backtrack(int n, int open, int close, StringBuilder sb, List<String> out) {
        if (open == n && close == n) {
            out.add(sb.toString());
            return;
        }
        if (open < n) {
            sb.append('(');
            backtrack(n, open + 1, close, sb, out);
            sb.deleteCharAt(sb.length() - 1);
        }
        if (close < open) {
            sb.append(')');
            backtrack(n, open, close + 1, sb, out);
            sb.deleteCharAt(sb.length() - 1);
        }
    }

    private static List<String> generate(int n) {
        List<String> res = new ArrayList<>();
        backtrack(n, 0, 0, new StringBuilder(), res);
        return res;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            int n = Integer.parseInt(br.readLine().trim());
            List<String> ans = generate(n);
            for (int i = 0; i < ans.size(); ++i) {
                out.append(ans.get(i));
                if (i + 1 < ans.size()) out.append(' ');
            }
            if (tc + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

