import sys

def generate(n: int):
    res = []
    def backtrack(s: str, open_cnt: int, close_cnt: int):
        if len(s) == 2 * n:
            res.append(s)
            return
        if open_cnt < n:
            backtrack(s + '(', open_cnt + 1, close_cnt)
        if close_cnt < open_cnt:
            backtrack(s + ')', open_cnt, close_cnt + 1)
    backtrack('', 0, 0)
    return res

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    T = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(T):
        n = int(data[idx]); idx += 1
        ans = generate(n)
        out_lines.append(' '.join(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

